class Solution:
    def uniqueMorseRepresentations(self, words):
        code = [".-", "-...", "-.-.", "-..", ".", "..-.", "--.", "....", "..", ".---", "-.-", ".-..", "--", "-.", "---", ".--.", "--.-", ".-.", "...", "-", "..-", "...-", ".--", "-..-", "-.--", "--.."]
        results = []
        for w in words:
            enc = ""
            for ch in w:
                enc += code[ord(ch) - 97]
            if enc not in results:
                results.append(enc)
        return len(results)

