var uniqueMorseRepresentations = function(words) {
    const code = [".-", "-...", "-.-.", "-..", ".", "..-.", "--.", "....", "..", ".---", "-.-", ".-..", "--", "-.", "---", ".--.", "--.-", ".-.", "...", "-", "..-", "...-", ".--", "-..-", "-.--", "--.."];
    const seen = new Set();
    for (const w of words) {
        let enc = "";
        for (const c of w) enc += code[c.charCodeAt(0) - 97];
        seen.add(enc);
    }
    return seen.size;
};
